import React from 'react';
import { Link } from 'react-router-dom';
import {
  useInView,
  HOME_SECTION_IN_VIEW_ROOT_MARGIN,
  HOME_SECTION_IN_VIEW_THRESHOLD,
} from '../../hooks/useInView';
import './WhyChooseUs.css';

const WhyChooseUs = () => {
  const [contentRef, contentVisible] = useInView(
    HOME_SECTION_IN_VIEW_THRESHOLD,
    HOME_SECTION_IN_VIEW_ROOT_MARGIN
  );

  return (
    <section className="why-choose-us">
      <div className="container">
        <div
          ref={contentRef}
          className={`why-choose-content reveal-group ${contentVisible ? 'is-visible' : ''}`}
        >
          <h2 className="section-title reveal-item">Why choose us</h2>
          <div className="qualities-grid">
            <div className="quality-card reveal-item">
              <div className="quality-icon">{'\u{1F3E2}'}</div>
              <h3>Built for small business</h3>
              <p>
                We work with SMEs, sole traders, and individuals who need dependable compliance and
                clear numbers—not jargon.
              </p>
            </div>
            <div className="quality-card reveal-item">
              <div className="quality-icon">{'\u{2699}'}</div>
              <h3>Structured delivery</h3>
              <p>
                Agreed scope, realistic timelines, and consistent communication so you know what happens
                next.
              </p>
            </div>
            <div className="quality-card reveal-item">
              <div className="quality-icon">{'\u{1F3AF}'}</div>
              <h3>Practical advice</h3>
              <p>
                Recommendations you can act on, aligned to UK rules and your stage of business.
              </p>
            </div>
          </div>
          <div className="cta-center reveal-item">
            <Link to="/contact" className="btn-primary btn-large">
              Submit Your Query
            </Link>
          </div>
        </div>
      </div>
    </section>
  );
};

export default WhyChooseUs;
